import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';

const MyReturns = () => {
  const [returns, setReturns] = useState([]);
  const [loading, setLoading] = useState(true);

  // Mock return data
  const mockReturns = [
    {
      id: 1,
      carName: 'Tesla Model S',
      carImage: 'https://via.placeholder.com/100x60?text=Tesla',
      bookingId: 1,
      returnDate: '2024-01-20',
      returnLocation: 'Downtown Office',
      status: 'pending',
      lateFee: 0,
      damageCharges: 0,
      totalAmount: 750,
      bookingEndDate: '2024-01-20'
    },
    {
      id: 2,
      carName: 'BMW X5',
      carImage: 'https://via.placeholder.com/100x60?text=BMW',
      bookingId: 2,
      returnDate: '2024-01-05',
      returnLocation: 'Airport Branch',
      status: 'completed',
      lateFee: 0,
      damageCharges: 0,
      totalAmount: 600,
      bookingEndDate: '2024-01-05'
    },
    {
      id: 3,
      carName: 'Mercedes C-Class',
      carImage: 'https://via.placeholder.com/100x60?text=Mercedes',
      bookingId: 3,
      returnDate: '2024-02-03',
      returnLocation: 'Downtown Office',
      status: 'scheduled',
      lateFee: 0,
      damageCharges: 0,
      totalAmount: 200,
      bookingEndDate: '2024-02-03'
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setReturns(mockReturns);
      setLoading(false);
    }, 500);
  }, []);

  const handleInitiateReturn = (returnId) => {
    alert('Return initiated! Our team will contact you shortly.');
    setReturns(returns.map(ret => 
      ret.id === returnId 
        ? { ...ret, status: 'pending' } 
        : ret
    ));
  };

  const getStatusBadge = (status) => {
    const statusClasses = {
      scheduled: 'status-pending',
      pending: 'status-active',
      completed: 'status-completed',
      late: 'status-cancelled'
    };
    return (
      <span className={`status-badge ${statusClasses[status]}`}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    );
  };

  return (
    <div className="dashboard-page">
      <Sidebar />
      
      <div className="dashboard-content">
        <div className="page-header">
          <h1>My Returns</h1>
          <p>Manage your car returns</p>
        </div>

        {/* Returns Info */}
        <div className="info-banner">
          <p>💡 You can initiate a return up to 24 hours before your scheduled return date.</p>
        </div>

        {/* Returns List */}
        {loading ? (
          <div className="loading">Loading returns...</div>
        ) : returns.length === 0 ? (
          <div className="empty-state">
            <p>No returns found</p>
          </div>
        ) : (
          <div className="returns-list">
            {returns.map(returnItem => (
              <div key={returnItem.id} className="return-card">
                <div className="return-car-image">
                  <img 
                    src={returnItem.carImage} 
                    alt={returnItem.carName}
                    onError={(e) => {
                      e.target.src = 'https://via.placeholder.com/100x60?text=Car';
                    }}
                  />
                </div>
                
                <div className="return-details">
                  <h3>{returnItem.carName}</h3>
                  <div className="return-info">
                    <p><strong>Booking ID:</strong> #{returnItem.bookingId}</p>
                    <p><strong>Scheduled Return:</strong> {returnItem.returnDate}</p>
                    <p><strong>Return Location:</strong> {returnItem.returnLocation}</p>
                  </div>
                </div>

                <div className="return-charges">
                  <div className="charge-item">
                    <span>Rental Amount:</span>
                    <span>₱{returnItem.totalAmount.toLocaleString()}</span>
                  </div>
                  <div className="charge-item">
                    <span>Late Fee:</span>
                    <span>₱{returnItem.lateFee.toLocaleString()}</span>
                  </div>
                  <div className="charge-item">
                    <span>Damage Charges:</span>
                    <span>₱{returnItem.damageCharges.toLocaleString()}</span>
                  </div>
                  <div className="charge-item total">
                    <span>Total:</span>
                    <span>₱{(returnItem.totalAmount + returnItem.lateFee + returnItem.damageCharges).toLocaleString()}</span>
                  </div>
                </div>

                <div className="return-actions">
                  {getStatusBadge(returnItem.status)}
                  
                  {(returnItem.status === 'scheduled' || returnItem.status === 'pending') && (
                    <>
                      <button 
                        className="btn btn-primary"
                        onClick={() => handleInitiateReturn(returnItem.id)}
                      >
                        {returnItem.status === 'scheduled' ? 'Initiate Return' : 'Track Return'}
                      </button>
                      <button className="btn btn-secondary">
                        View Details
                      </button>
                    </>
                  )}
                  
                  {returnItem.status === 'completed' && (
                    <button className="btn btn-secondary">
                      Download Receipt
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MyReturns;
